import{_ as o,o as e,c as t,a2 as r}from"./chunks/framework.Cr-Z7ngm.js";const g=JSON.parse('{"title":"APP网络连接排查","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"troubleshooting/network-connection.md","filePath":"zh-CN/troubleshooting/network-connection.md"}'),n={name:"troubleshooting/network-connection.md"};function l(p,a,i,s,h,c){return e(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="app网络连接排查" tabindex="-1">APP网络连接排查 <a class="header-anchor" href="#app网络连接排查" aria-label="Permalink to &quot;APP网络连接排查&quot;">​</a></h1><p>主要用于 APP 卡顿、连接不上、页面加载慢等网络问题的排查。</p><h2 id="网络诊断工具" tabindex="-1">网络诊断工具 <a class="header-anchor" href="#网络诊断工具" aria-label="Permalink to &quot;网络诊断工具&quot;">​</a></h2><p>长桥提供在线网络诊断工具，可检测网络连接状况。</p><p>访问方式：<br><a href="http://detect.longbridge-inc.com/" target="_blank" rel="noreferrer">- 网页访问</a></p><ul><li>App 入口：设置 - 通用 - 使用浏览器打开网络诊断</li></ul><h3 id="检测功能" tabindex="-1">检测功能 <a class="header-anchor" href="#检测功能" aria-label="Permalink to &quot;检测功能&quot;">​</a></h3><ol><li><strong>浏览器和系统信息</strong>：检测浏览器、操作系统及 Cookie/localStorage 状态</li><li><strong>网络速度测试</strong>：测量 LongBridge API、WebSocket 连接和静态资源的延迟，以及第三方服务（Google、Bing、Baidu）的连接性能</li><li><strong>隐私保障</strong>：工具不收集或存储私人信息，仅收集诊断所需的技术数据</li></ol><h2 id="常见问题排查" tabindex="-1">常见问题排查 <a class="header-anchor" href="#常见问题排查" aria-label="Permalink to &quot;常见问题排查&quot;">​</a></h2><h3 id="vpn-或代理导致网络问题" tabindex="-1">VPN 或代理导致网络问题 <a class="header-anchor" href="#vpn-或代理导致网络问题" aria-label="Permalink to &quot;VPN 或代理导致网络问题&quot;">​</a></h3><p><strong>现象一：中国 IP + global 快 + 大陆慢</strong></p><p>Local IP 显示为中国地址，但 global 地址连接快（约 50ms），mainland 地址连接慢（约 500ms），第三方服务（Google）连接快。</p><p>原因：可能使用了 VPN 或代理，导致访问中国服务的连接变慢。</p><p>解决方案：关闭 VPN 或代理，重启 App 并重新测试。</p><p><strong>现象二：海外 IP + 大陆快 + global 慢</strong></p><p>Local IP 显示为海外地址，但 mainland 地址连接快（约 100ms），global 地址连接慢（约 800ms）。</p><p>原因：可能使用了代理手段，导致访问海外服务器变慢。</p><p>解决方案：关闭 VPN 或代理，重启 App 并重新测试。</p><p><strong>现象三：部分快部分慢（无规律）</strong></p><p>部分检测项响应快，部分异常慢，无明显规律。</p><p>原因：可能使用了代理但未配置合理的代理策略。</p><p>解决方案：关闭 VPN 或代理，重启 App 并重新测试。</p><h3 id="用户网络质量问题" tabindex="-1">用户网络质量问题 <a class="header-anchor" href="#用户网络质量问题" aria-label="Permalink to &quot;用户网络质量问题&quot;">​</a></h3><p><strong>现象：所有检测项都很慢</strong></p><p>global 和 mainland 地址连接均慢（600-1200ms），第三方服务也慢（500-1500ms）。</p><p>原因：网络带宽不足或网络质量不稳定。</p><p>解决方案：检查本地网络连接，重启路由器或切换到其他网络（如手机热点）。</p><h3 id="长桥服务问题" tabindex="-1">长桥服务问题 <a class="header-anchor" href="#长桥服务问题" aria-label="Permalink to &quot;长桥服务问题&quot;">​</a></h3><p><strong>现象：所有 API/WS 检测均失败</strong></p><p>global 和 mainland 地址均无法连接，但部分第三方服务可以连接（50-150ms）。</p><p>原因：长桥服务可能出现故障，或用户本地对部分地址做了安全防护。</p><p>解决方案：请联系客服确认服务状态。如确认是服务故障，请等待恢复通知。</p><h2 id="ip-地址查询工具" tabindex="-1">IP 地址查询工具 <a class="header-anchor" href="#ip-地址查询工具" aria-label="Permalink to &quot;IP 地址查询工具&quot;">​</a></h2><p>如需查询本地 IP 地址：</p><ul><li><a href="https://www.ip138.com/" target="_blank" rel="noreferrer">https://www.ip138.com/</a></li><li><a href="https://ip.tool.chinaz.com/" target="_blank" rel="noreferrer">https://ip.tool.chinaz.com/</a></li></ul>',35)])])}const P=o(n,[["render",l]]);export{g as __pageData,P as default};
